onClick:
{{
  (async function() {
    if (!inp_new_model_name.text || !inp_new_model_weight.text) {
      showAlert('Please enter both model name and weight', 'warning');
      return;
    }
    qry_model_insert.run(
      async function() {
        const newModelId = qry_model_insert.data[0]?.model_id;
        const newModelName = qry_model_insert.data[0]?.model_name;
        await qry_models_list.run();
        await new Promise(resolve => setTimeout(resolve, 150));
        await storeValue('autoSelectModelId', newModelId);
        await storeValue('autoSelectModelName', newModelName);
        resetWidget('sel_model', true);
        closeModal('Modal1');
        showAlert('Model added successfully', 'success');
        resetWidget('inp_new_model_name', true);
        resetWidget('inp_new_model_weight', true);
        // Fix the asset if opened from review context
        if (appsmith.store.reviewContext) {
          await qry_asset_review_update.run({
            assetId: appsmith.store.reviewContext.asset_id,
            itemTypeId: tbl_unmatched_assets.selectedRow.item_type,
            makeId: appsmith.store.reviewContext.make_id,
            modelId: newModelId
          });
          await storeValue('reviewContext', null);
          await qry_unmatched_assets.run();
          await qry_booked_assets.run();
        }
      },
      function(error) {
        showAlert('Failed to add model — ' + error.message, 'error');
      }
    );
  })()
}}
